import org.junit.Test
import kotlin.test.*

/**
 * Tests for yield() behavior with delayed tasks.
 * See https://github.com/Kotlin/kotlinx.coroutines/issues/[issue-number]
 */
class YieldDelayTest : TestBase() {

    @Test
    fun testYieldAfterDelayExpired() = runBlocking {
        val result = mutableListOf<String>()

        launch(start = CoroutineStart.UNDISPATCHED) {
            delay(1)
            result.add("delayed")
        }

        Thread.sleep(100) // Wait for delay to expire
        yield()
        result.add("main")

        // Wait for all coroutines to complete
        Thread.sleep(10)

        // The delayed coroutine should execute first, before the main coroutine resumes
        assertEquals(listOf("delayed", "main"), result)
    }

    @Test
    fun testYieldWithMultipleDelayedTasks() = runBlocking {
        val result = mutableListOf<String>()

        launch(start = CoroutineStart.UNDISPATCHED) {
            delay(1)
            result.add("delayed1")
        }

        launch(start = CoroutineStart.UNDISPATCHED) {
            delay(2)
            result.add("delayed2")
        }

        Thread.sleep(100) // Wait for both delays to expire
        yield()
        result.add("main")

        // Wait for all coroutines to complete
        Thread.sleep(10)

        // Both delayed coroutines should execute before main resumes
        assertEquals(3, result.size)
        assertTrue(result.contains("delayed1"))
        assertTrue(result.contains("delayed2"))
        assertEquals("main", result[2], "Main should be last")
    }

    @Test
    fun testYieldBeforeDelayExpires() = runBlocking {
        val result = mutableListOf<String>()

        launch(start = CoroutineStart.UNDISPATCHED) {
            delay(100)
            result.add("delayed")
        }

        // Don't wait - yield immediately
        yield()
        result.add("main")

        // The main coroutine should resume immediately since delay hasn't expired
        assertEquals(listOf("main"), result)

        // Now wait for the delayed task
        Thread.sleep(200)
        assertEquals(listOf("main", "delayed"), result)
    }
}
"}

